class Solution:
    def longestAlternatingSubarray(self, nums: List[int], threshold: int) -> int:
        max_len = 0
        n = len(nums)

        for l in range(n):
            if nums[l] % 2 != 0:
                continue  # Skip if starting element is not even
            if nums[l] > threshold:
                continue  # Skip if starting element exceeds threshold

            # Start of valid subarray
            r = l
            while r < n:
                if nums[r] > threshold:
                    break  # Invalid element, break the loop
                # Check parity alternation
                if r > l and (nums[r] % 2) == (nums[r - 1] % 2):
                    break  # Parity not alternating, break the loop
                r += 1

            # Update max length
            max_len = max(max_len, r - l)

        return max_len
